import{_ as e,c as l,S as d,o as a}from"./chunks/framework.BjmDYXuv.js";const f=JSON.parse('{"title":"Backend Service","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"internal/backend.md","filePath":"internal/backend.md","lastUpdated":1775813285000}'),s={name:"internal/backend.md"};function i(o,t,n,r,c,h){return a(),l("div",null,t[0]||(t[0]=[d('<h1 id="backend-service" tabindex="-1">Backend Service <a class="header-anchor" href="#backend-service" aria-label="Permalink to &quot;Backend Service&quot;">​</a></h1><p>The ColliderML backend is a <strong>FastAPI</strong> application that accepts simulation requests, manages user credits, dispatches jobs to NERSC Perlmutter via the Superfacility API, and hosts benchmark leaderboards.</p><p>Source: <code>colliderml-production/backend/</code></p><h2 id="technology-stack" tabindex="-1">Technology stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology stack&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Layer</th><th style="text-align:left;">Choice</th></tr></thead><tbody><tr><td style="text-align:left;">Framework</td><td style="text-align:left;">FastAPI 0.115+</td></tr><tr><td style="text-align:left;">Database</td><td style="text-align:left;">Supabase (PostgreSQL 14+) via <code>asyncpg</code></td></tr><tr><td style="text-align:left;">Authentication</td><td style="text-align:left;">HuggingFace OAuth bearer tokens</td></tr><tr><td style="text-align:left;">Job dispatch</td><td style="text-align:left;">NERSC SFAPI (<code>sfapi-client&gt;=0.1.0</code>)</td></tr><tr><td style="text-align:left;">Container runtime</td><td style="text-align:left;">Shifter on Perlmutter</td></tr><tr><td style="text-align:left;">Output storage</td><td style="text-align:left;">HuggingFace Datasets</td></tr><tr><td style="text-align:left;">Templating</td><td style="text-align:left;">Jinja2 (sbatch scripts)</td></tr><tr><td style="text-align:left;">Email</td><td style="text-align:left;">aiosmtplib (optional)</td></tr></tbody></table><h2 id="routes" tabindex="-1">Routes <a class="header-anchor" href="#routes" aria-label="Permalink to &quot;Routes&quot;">​</a></h2><h3 id="user-routes-v1" tabindex="-1">User routes (<code>/v1/*</code>) <a class="header-anchor" href="#user-routes-v1" aria-label="Permalink to &quot;User routes (`/v1/*`)&quot;">​</a></h3><p>All require <code>Authorization: Bearer &lt;hf-token&gt;</code>.</p><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Path</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/v1/simulate</code></td><td style="text-align:left;">Submit a simulation request</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/requests/{request_id}</code></td><td style="text-align:left;">Status + output URI for one request</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/requests</code></td><td style="text-align:left;">List current user&#39;s requests (paginated, limit=50)</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/me</code></td><td style="text-align:left;">User profile: username, email, credits, timestamps</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/me/transactions</code></td><td style="text-align:left;">Credit ledger entries (paginated, limit=100)</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/datasets</code></td><td style="text-align:left;">Static catalogue of 21 dataset variants</td></tr></tbody></table><h3 id="benchmark-routes-v1-benchmark" tabindex="-1">Benchmark routes (<code>/v1/benchmark/*</code>) <a class="header-anchor" href="#benchmark-routes-v1-benchmark" aria-label="Permalink to &quot;Benchmark routes (`/v1/benchmark/*`)&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Path</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/benchmark/tasks</code></td><td style="text-align:left;">List all benchmark tasks with metrics</td></tr><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/v1/benchmark/{task}/submit</code></td><td style="text-align:left;">Upload predictions (Parquet), auto-score, award credits</td></tr><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/v1/benchmark/{task}/reproduce/{id}</code></td><td style="text-align:left;">Reproduce a submission; earn 20 credits if within 2%</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/v1/leaderboard/{task}</code></td><td style="text-align:left;">Leaderboard for a task (limit=100)</td></tr></tbody></table><h3 id="admin-routes-admin" tabindex="-1">Admin routes (<code>/admin/*</code>) <a class="header-anchor" href="#admin-routes-admin" aria-label="Permalink to &quot;Admin routes (`/admin/*`)&quot;">​</a></h3><p>Require <code>X-Admin-Token: &lt;shared-secret&gt;</code> header.</p><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Path</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/admin/freeze?frozen={bool}</code></td><td style="text-align:left;">Kill switch — pause all new submissions</td></tr><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/admin/grant</code></td><td style="text-align:left;">Grant/deduct credits: <code>{hf_username, delta, reason}</code></td></tr><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/admin/ban</code></td><td style="text-align:left;">Ban/unban a user: <code>{hf_username, banned}</code></td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/admin/usage?limit=20</code></td><td style="text-align:left;">Top users by node-hours this month</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/admin/analytics/channels</code></td><td style="text-align:left;">Request count + node-hours per channel</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/admin/analytics/daily?days=30</code></td><td style="text-align:left;">Daily node-hours time series</td></tr><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/admin/analytics/failures</code></td><td style="text-align:left;">Failure rate this month</td></tr></tbody></table><h3 id="webhook-routes-webhooks" tabindex="-1">Webhook routes (<code>/webhooks/*</code>) <a class="header-anchor" href="#webhook-routes-webhooks" aria-label="Permalink to &quot;Webhook routes (`/webhooks/*`)&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Path</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>POST</code></td><td style="text-align:left;"><code>/webhooks/github</code></td><td style="text-align:left;">GitHub PR-merged webhook (HMAC-SHA256 verified)</td></tr></tbody></table><h3 id="health" tabindex="-1">Health <a class="header-anchor" href="#health" aria-label="Permalink to &quot;Health&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Path</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>GET</code></td><td style="text-align:left;"><code>/healthz</code></td><td style="text-align:left;">Readiness probe</td></tr></tbody></table><h2 id="database-schema" tabindex="-1">Database schema <a class="header-anchor" href="#database-schema" aria-label="Permalink to &quot;Database schema&quot;">​</a></h2><p>Six core tables, one view:</p><h3 id="users" tabindex="-1"><code>users</code> <a class="header-anchor" href="#users" aria-label="Permalink to &quot;`users`&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Type</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hf_username</code></td><td style="text-align:left;">text PK</td><td style="text-align:left;">HuggingFace username</td></tr><tr><td style="text-align:left;"><code>email</code></td><td style="text-align:left;">text</td><td style="text-align:left;">nullable</td></tr><tr><td style="text-align:left;"><code>credits</code></td><td style="text-align:left;">numeric(10,3)</td><td style="text-align:left;">Current balance</td></tr><tr><td style="text-align:left;"><code>banned</code></td><td style="text-align:left;">bool</td><td style="text-align:left;">default false</td></tr><tr><td style="text-align:left;"><code>created_at</code></td><td style="text-align:left;">timestamptz</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>last_seen_at</code></td><td style="text-align:left;">timestamptz</td><td style="text-align:left;">Updated on every auth</td></tr><tr><td style="text-align:left;"><code>notes</code></td><td style="text-align:left;">text</td><td style="text-align:left;">Operator notes</td></tr></tbody></table><h3 id="credit-transactions" tabindex="-1"><code>credit_transactions</code> <a class="header-anchor" href="#credit-transactions" aria-label="Permalink to &quot;`credit_transactions`&quot;">​</a></h3><p>Append-only ledger. Every credit movement is recorded.</p><table><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Type</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><code>id</code></td><td style="text-align:left;">bigserial PK</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>hf_username</code></td><td style="text-align:left;">text FK</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>delta</code></td><td style="text-align:left;">numeric(10,3)</td><td style="text-align:left;">Positive = credit, negative = debit</td></tr><tr><td style="text-align:left;"><code>reason</code></td><td style="text-align:left;">text</td><td style="text-align:left;"><code>signup</code>, <code>spent_on_request</code>, <code>reconciliation_refund</code>, <code>refund_submit_failed</code>, <code>refund_job_failed</code>, <code>beat_&lt;task&gt;</code>, <code>github_pr_merged</code>, <code>admin_grant</code></td></tr><tr><td style="text-align:left;"><code>metadata</code></td><td style="text-align:left;">jsonb</td><td style="text-align:left;">Request hash, submission ID, PR URL, etc.</td></tr><tr><td style="text-align:left;"><code>created_at</code></td><td style="text-align:left;">timestamptz</td><td style="text-align:left;"></td></tr></tbody></table><h3 id="simulation-requests" tabindex="-1"><code>simulation_requests</code> <a class="header-anchor" href="#simulation-requests" aria-label="Permalink to &quot;`simulation_requests`&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Type</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><code>id</code></td><td style="text-align:left;">uuid PK</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>hf_username</code></td><td style="text-align:left;">text FK</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>channel</code></td><td style="text-align:left;">text</td><td style="text-align:left;">Physics channel name</td></tr><tr><td style="text-align:left;"><code>events</code></td><td style="text-align:left;">int</td><td style="text-align:left;">1–100,000</td></tr><tr><td style="text-align:left;"><code>pileup</code></td><td style="text-align:left;">int</td><td style="text-align:left;">0–200</td></tr><tr><td style="text-align:left;"><code>seed</code></td><td style="text-align:left;">int</td><td style="text-align:left;">default 42</td></tr><tr><td style="text-align:left;"><code>config_hash</code></td><td style="text-align:left;">text</td><td style="text-align:left;">SHA-256 of (channel, events, pileup, seed)</td></tr><tr><td style="text-align:left;"><code>state</code></td><td style="text-align:left;">text</td><td style="text-align:left;"><code>queued</code> → <code>submitted</code> → <code>running</code> → <code>completed</code> | <code>failed</code> | <code>cancelled</code></td></tr><tr><td style="text-align:left;"><code>nersc_jobid</code></td><td style="text-align:left;">text</td><td style="text-align:left;">SLURM job ID</td></tr><tr><td style="text-align:left;"><code>estimated_node_hours</code></td><td style="text-align:left;">numeric(10,3)</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>actual_node_hours</code></td><td style="text-align:left;">numeric(10,3)</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>credits_charged</code></td><td style="text-align:left;">numeric(10,3)</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>output_hf_repo</code></td><td style="text-align:left;">text</td><td style="text-align:left;"><code>CERN/ColliderML-Service-&lt;id&gt;</code></td></tr><tr><td style="text-align:left;"><code>error_message</code></td><td style="text-align:left;">text</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><code>created_at</code>, <code>updated_at</code></td><td style="text-align:left;">timestamptz</td><td style="text-align:left;"></td></tr></tbody></table><p>Unique constraint on <code>config_hash</code> where state in <code>(queued, submitted, running, completed)</code> — prevents duplicate in-flight requests.</p><h3 id="global-config" tabindex="-1"><code>global_config</code> <a class="header-anchor" href="#global-config" aria-label="Permalink to &quot;`global_config`&quot;">​</a></h3><p>Single-row table (id=1).</p><table><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Default</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>monthly_node_hours_cap</code></td><td style="text-align:left;">500</td><td style="text-align:left;">Global monthly ceiling</td></tr><tr><td style="text-align:left;"><code>submissions_frozen</code></td><td style="text-align:left;">false</td><td style="text-align:left;">Kill switch</td></tr><tr><td style="text-align:left;"><code>seed_credits</code></td><td style="text-align:left;">10</td><td style="text-align:left;">Credits granted on first sign-in</td></tr></tbody></table><h3 id="benchmark-submissions-benchmark-bests-benchmark-reproductions" tabindex="-1"><code>benchmark_submissions</code>, <code>benchmark_bests</code>, <code>benchmark_reproductions</code> <a class="header-anchor" href="#benchmark-submissions-benchmark-bests-benchmark-reproductions" aria-label="Permalink to &quot;`benchmark_submissions`, `benchmark_bests`, `benchmark_reproductions`&quot;">​</a></h3><p>Leaderboard tables tracking per-task submissions, current bests per metric, and reproduction attempts.</p><h3 id="gh-hf-mapping" tabindex="-1"><code>gh_hf_mapping</code> <a class="header-anchor" href="#gh-hf-mapping" aria-label="Permalink to &quot;`gh_hf_mapping`&quot;">​</a></h3><p>Maps GitHub usernames to HuggingFace usernames for automated credit grants on PR merges.</p><h3 id="monthly-usage-view" tabindex="-1"><code>monthly_usage</code> (view) <a class="header-anchor" href="#monthly-usage-view" aria-label="Permalink to &quot;`monthly_usage` (view)&quot;">​</a></h3><p>Aggregates <code>node_hours</code> and <code>n_requests</code> per user for the current calendar month.</p><h2 id="authentication-flow" tabindex="-1">Authentication flow <a class="header-anchor" href="#authentication-flow" aria-label="Permalink to &quot;Authentication flow&quot;">​</a></h2><ol><li>Extract <code>Authorization: Bearer &lt;token&gt;</code> header</li><li>Verify against <code>https://huggingface.co/api/whoami-v2</code></li><li>First sign-in: create user row, grant <code>seed_credits</code>, record <code>signup</code> transaction</li><li>Check <code>banned</code> flag — reject with 403 if true</li><li>Update <code>last_seen_at</code>, return user dict</li></ol><h2 id="credit-system" tabindex="-1">Credit system <a class="header-anchor" href="#credit-system" aria-label="Permalink to &quot;Credit system&quot;">​</a></h2><p><strong>Unit:</strong> 1 credit = 1 node-hour on Perlmutter CPU queue.</p><p><strong>Cost formula:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>base_seconds = channel_base[channel]   # 5s–90s per event</span></span>\n<span class="line"><span>pileup_factor = 1 + pileup / 50</span></span>\n<span class="line"><span>overhead = madgraph_overhead[channel]   # 0 or 300s</span></span>\n<span class="line"><span>node_hours = (overhead + base_seconds * events * pileup_factor) / 3600</span></span></code></pre></div><p><strong>Pre-submission gates</strong> (checked in order):</p><ol><li>Banned? → 403</li><li>Frozen? → 503</li><li>Burst: ≥10 submissions in 5 min → 429</li><li>Duplicate: same config_hash completed in 7 days → 409</li><li>Monthly cap: <code>used + est &gt; cap</code> → 503</li><li>Balance: <code>credits &lt; est</code> → 402</li><li>Atomic deduction inside a database transaction</li></ol><p><strong>Refunds:</strong> Automatic on submission failure, job failure, or over-estimation (reconciliation).</p><p><strong>Earning credits:</strong></p><ul><li>Beat a leaderboard metric: 30–50 credits per metric</li><li>Reproduce a submission (within 2%): 20 credits</li><li>GitHub PR merged with recognized labels: 10–200 credits</li><li>Admin grant: arbitrary</li></ul>',48)]))}const u=e(s,[["render",i]]);export{f as __pageData,u as default};
